  "code": "    largest = 1
    # Handle factor 2 separately
    while n % 2 == 0:
        largest = 2
        n //= 2

    # Check odd factors from 3 upwards
    factor = 3
    while factor * factor <= n:
        while n % factor == 0:
            largest = factor
            n //= factor
        factor += 2

    # If remaining n is a prime greater than 2
    if n > 1:
        largest = n

    return largest",
